mapper.select:
select r.id, r.strategy_id as strategyId, r.strategy_version_id as strategyVersionId, r.engine_type as engineType, r.script_type as scriptType, i.strategy_name as strategyName, i.strategy_code as strategyCode, v.version_no as versionNo, r.run_type as runType, r.trigger_source as triggerSource, r.run_status as runStatus, r.data_snapshot_date as dataSnapshotDate, r.start_time as startTime, r.end_time as endTime, r.duration_ms as durationMs, r.result_count as resultCount, r.error_message as errorMessage, r.created_time as createdTime from t_strategy_run r left join t_strategy_info i on r.strategy_id = i.id left join t_strategy_version v on r.strategy_version_id = v.id where 1 = 1
and r.strategy_id = #{request.strategyId}
and i.strategy_name like CONCAT('%', #{request.strategyName}, '%')
and r.run_status = #{request.runStatus}
order by r.id desc
